export function formatPlays(n: number): string {
  if (n >= 1000) return `${(n / 1000).toFixed(1)}k`;
  return String(n);
}

export function totalDuration(list: Track[]): string {
  let total = 0;
  for (const t of list) {
    const parts = t.duration.split(":").map(Number);
    if (parts.length === 2) total += (parts[0] ?? 0) * 60 + (parts[1] ?? 0);
  }
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  return h > 0 ? `${h}h ${m}m` : `${m}m`;
}

export function tracksByArtist(name: string): Track[] {
  return tracks.filter((t) => t.artist.toLowerCase().includes(name.toLowerCase()));
}

